1	import { Component, Inject } from '@angular/core';
2	import { FormControl } from '@angular/forms';
3	import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
4	import { Observable } from 'rxjs';
5	import { map, startWith } from 'rxjs/operators';
6	import { ORIGINS, ORIGIN_DEFAULTS, OFFICES, SAMPLE_STOPS, statusLabel, directionLabel } from '../helpers/sample.status';
7	
8	interface CustomerOption {
9	  customers_id: number;
10	  customers_name: string;
11	}
12	
13	// Create a new sample. Origin drives direction + initial status (server confirms).
14	@Component({
15	  selector: 'sample-create-dialog',
16	  standalone: false,
17	  templateUrl: './create-dialog.component.html',
18	  styleUrls: ['./create-dialog.component.scss']
19	})
20	export class CreateDialogComponent {
21	  origins = ORIGINS;
22	  offices = OFFICES;
23	  stops = SAMPLE_STOPS;
24	  couriers = [
25	    { value: 'ups', label: 'UPS' },
26	    { value: 'fedex', label: 'FedEx' },
27	    { value: 'aae', label: 'AAE' },
28	    { value: 'bombino', label: 'Bombino' }
29	  ];
30	  customers: CustomerOption[] = [];
31	  customerControl = new FormControl<CustomerOption | string | null>(null);
32	  filteredCustomers$: Observable<CustomerOption[]>;
33	
34	  // Optional photo to attach on creation. The sample has no id until the server
35	  // creates it, so we only capture the file + a preview here; the parent uploads
36	  // it (presigned flow) once it has the new sample_id_pk.
37	  photoFile: File | null = null;
38	  photoPreview: string | null = null;
39	  photoError: string | null = null;
40	
41	  model: any = {
42	    origin: 'factory_request',
43	    sample_name: '',
44	    quantity: null,
45	    retail_price: null,
46	    fob_cost: null,
47	    customer_id_fk: null,
48	    courier: null,
49	    tracking_number: '',
50	    factory_id_fk: null,
51	    office_location: null,
52	    next_stop: null,
53	    final_destination: null,
54	    notes: ''
55	  };
56	
57	  constructor(
58	    public dialogRef: MatDialogRef<CreateDialogComponent>,
59	    @Inject(MAT_DIALOG_DATA) public data: { customers?: CustomerOption[] } | null
60	  ) {
61	    this.customers = (data && data.customers ? data.customers : [])
62	      .filter((c: any) => c && c.customers_id != null)
63	      .map((c: any) => ({ customers_id: Number(c.customers_id), customers_name: c.customers_name || `Customer #${c.customers_id}` }));
64	    this.filteredCustomers$ = this.customerControl.valueChanges.pipe(
65	      startWith(''),
66	      map(value => this.filterCustomers(value))
67	    );
68	  }
69	
70	  originLabel(origin: string): string {
71	    const map: any = {
72	      factory_request: 'We request from factory',
73	      factory_offer: 'Factory offers to us',
74	      usa_bought: 'Bought in USA (send out)',
75	      customer: 'Customer (send from Ningbo)'
76	    };
77	    return map[origin] || origin;
78	  }
79	
80	  onOriginChange(): void {
81	    if (this.model.origin !== 'customer') {
82	      this.model.customer_id_fk = null;
83	      this.customerControl.setValue(null, { emitEvent: false });
84	      return;
85	    }
86	    this.model.office_location = 'Ningbo';
87	    this.model.next_stop = 'Customer';
88	    this.model.final_destination = 'Customer';
89	  }
90	
91	  displayCustomer(value: CustomerOption | string | null): string {
92	    if (!value) return '';
93	    if (typeof value === 'string') return value;
94	    return value.customers_name || '';
95	  }
96	
97	  onCustomerSelected(customer: CustomerOption): void {
98	    this.model.customer_id_fk = customer ? customer.customers_id : null;
99	  }
100	
101	  private filterCustomers(value: CustomerOption | string | null): CustomerOption[] {
102	    const query = this.displayCustomer(value).trim().toLowerCase();
103	    if (!query) return this.customers.slice(0, 50);
104	    return this.customers
105	      .filter(c => (c.customers_name || '').toLowerCase().includes(query))
106	      .slice(0, 50);
107	  }
108	
109	  get previewStatus(): string {
110	    const def = ORIGIN_DEFAULTS[this.model.origin];
111	    return def ? `${statusLabel(def.initialStatus)} (${directionLabel(def.direction)})` : '';
112	  }
113	
114	  onPhotoSelected(event: Event): void {
115	    this.photoError = null;
116	    const input = event.target as HTMLInputElement;
117	    const file = input.files && input.files[0];
118	    if (!file) return;
119	    if (!file.type || !file.type.startsWith('image/')) {
120	      this.photoError = 'Please choose an image file.';
121	      input.value = '';
122	      return;
123	    }
124	    this.photoFile = file;
125	    const reader = new FileReader();
126	    reader.onload = () => { this.photoPreview = typeof reader.result === 'string' ? reader.result : null; };
127	    reader.readAsDataURL(file);
128	  }
129	
130	  removePhoto(): void {
131	    this.photoFile = null;
132	    this.photoPreview = null;
133	    this.photoError = null;
134	  }
135	
136	  // Final destination is the required route field. Next stop is optional: when it
137	  // is left blank the sample goes straight to its final destination, so we treat
138	  // the final destination as the next stop.
139	  get canSave(): boolean {
140	    const hasRoute = !!this.model.origin && !!this.model.final_destination;
141	    if (this.model.origin === 'customer') return hasRoute && !!this.model.customer_id_fk;
142	    return hasRoute;
143	  }
144	
145	  save(): void {
146	    if (!this.canSave) return;
147	    const model = { ...this.model };
148	    if (!model.next_stop) model.next_stop = model.final_destination;
149	    // __photoFile is consumed by the parent for the post-create upload; it is not
150	    // a persisted sample field (the parent strips it before calling createSample).
151	    this.dialogRef.close({ ...model, __photoFile: this.photoFile });
152	  }
153	
154	  cancel(): void { this.dialogRef.close(); }
155	}
