1	import { Component, OnInit } from '@angular/core';
2	import { MatDialog } from '@angular/material/dialog';
3	import { MatSnackBar } from '@angular/material/snack-bar';
4	import { firstValueFrom } from 'rxjs';
5	import {
6	  GridApi, GridReadyEvent, GridOptions, ColDef,
7	  CellValueChangedEvent, IDetailCellRendererParams
8	} from 'ag-grid-community';
9	import { TrackingService } from '../../helpers/services/tracking.service';
10	import { itemService } from '../../helpers/services/main.service';
11	import { SAMPLE_TRACKING_COLUMN_HEADERS_CONFIG } from '../../helpers/ag-grid/sample.tracking.config';
12	import { SamplePhotoRendererComponent, SampleStatusRendererComponent, TrackingLinkRendererComponent } from './renderers/sample-cell-renderers';
13	import { EventDialogComponent } from './event-dialog/event-dialog.component';
14	import { CreateDialogComponent } from './create-dialog/create-dialog.component';
15	import { DetailDialogComponent } from './detail-dialog/detail-dialog.component';
16	import { BoxGroupDialogComponent } from './box-group-dialog/box-group-dialog.component';
17	import { statusLabel } from './helpers/sample.status';
18	
19	@Component({
20	  selector: 'app-sample-tracking',
21	  standalone: false,
22	  templateUrl: './sample_tracking.component.html',
23	  styleUrls: ['./sample_tracking.component.scss']
24	})
25	export class SampleTrackingComponent implements OnInit {
26	  gridApi!: GridApi;
27	  columnDefs: ColDef[] = SAMPLE_TRACKING_COLUMN_HEADERS_CONFIG.columnDefs;
28	  rowData: any[] = [];
29	  loading = false;
30	  private customers: any[] = [];
31	  private customerNameById = new Map<number, string>();
32	
33	  gridOptions: GridOptions;
34	
35	  constructor(
36	    private trackingService: TrackingService,
37	    private coreApi: itemService,
38	    private dialog: MatDialog,
39	    private snackBar: MatSnackBar
40	  ) {
41	    this.gridOptions = {
42	      rowModelType: 'clientSide',
43	      masterDetail: true,
44	      detailRowAutoHeight: true,
45	      rowSelection: { mode: 'multiRow' } as any,
46	      defaultColDef: { resizable: true },
47	      getRowId: (p: any) => String(p.data.sample_id_pk),
48	      components: {
49	        samplePhotoRenderer: SamplePhotoRendererComponent,
50	        sampleStatusRenderer: SampleStatusRendererComponent,
51	        trackingLinkRenderer: TrackingLinkRendererComponent
52	      },
53	      // The detail row shows the sample's event timeline, loaded on expand.
54	      detailCellRendererParams: {
55	        detailGridOptions: {
56	          columnDefs: [
57	            { headerName: 'When', field: 'event_time', width: 180,
58	              valueFormatter: (p: any) => p.value ? new Date(p.value).toLocaleString() : '' },
59	            { headerName: 'Event', field: 'event_type', width: 130 },
60	            { headerName: 'From', field: 'from_status', width: 160,
61	              valueFormatter: (p: any) => statusLabel(p.value) },
62	            { headerName: 'To', field: 'to_status', width: 160,
63	              valueFormatter: (p: any) => statusLabel(p.value) },
64	            { headerName: 'Office', field: 'office_location', width: 110 },
65	            { headerName: 'By', field: 'event_user', width: 140 },
66	            { headerName: 'Notes', field: 'notes', flex: 1 }
67	          ],
68	          defaultColDef: { sortable: true, resizable: true }
69	        },
70	        getDetailRowData: (params: any) => {
71	          this.trackingService.getSampleEvents(params.data.sample_id_pk).subscribe({
72	            next: (events: any) => params.successCallback(events || []),
73	            error: () => params.successCallback([])
74	          });
75	        }
76	      } as IDetailCellRendererParams
77	    };
78	  }
79	
80	  ngOnInit(): void {
81	    // data loads on gridReady
82	  }
83	
84	  onGridReady(params: GridReadyEvent): void {
85	    this.gridApi = params.api;
86	    this.loadSamples();
87	  }
88	
89	  private async loadCustomers(): Promise<void> {
90	    try {
91	      const data: any = await firstValueFrom(this.coreApi.getCustomers());
92	      this.customers = data || [];
93	      this.customerNameById = new Map(
94	        this.customers
95	          .filter((c: any) => c.customers_id != null)
96	          .map((c: any) => [Number(c.customers_id), c.customers_name || `Customer #${c.customers_id}`])
97	      );
98	    } catch {
99	      this.customers = [];
100	      this.customerNameById = new Map();
101	    }
102	  }
103	
104	  private decorateSampleRows(rows: any[]): any[] {
105	    return (rows || []).map((row: any) => ({
106	      ...row,
107	      customer_name: row.customer_id_fk ? (this.customerNameById.get(Number(row.customer_id_fk)) || `Customer #${row.customer_id_fk}`) : ''
108	    }));
109	  }
110	
111	  async loadSamples(): Promise<void> {
112	    this.loading = true;
113	    try {
114	      if (!this.customers.length) await this.loadCustomers();
115	      const res: any = await firstValueFrom(
116	        this.trackingService.getSamples({ startRow: 0, endRow: 100, filterModel: {} })
117	      );
118	      this.rowData = this.decorateSampleRows((res && res.rows) ? res.rows : []);
119	    } catch (e) {
120	      this.toast('Failed to load samples');
121	      this.rowData = [];
122	    } finally {
123	      this.loading = false;
124	    }
125	  }
126	
127	  private getSelected(): any | null {
128	    const rows = this.gridApi ? this.gridApi.getSelectedRows() : [];
129	    return rows && rows.length ? rows[0] : null;
130	  }
131	
132	  private getSelectedIds(): number[] {
133	    const rows = this.gridApi ? this.gridApi.getSelectedRows() : [];
134	    return (rows || []).map((r: any) => r.sample_id_pk);
135	  }
136	
137	  async onOpenDetail(row?: any): Promise<void> {
138	    const sample = row || this.getSelected();
139	    if (!sample) { this.toast('Select a sample first'); return; }
140	    const ref = this.dialog.open(DetailDialogComponent, { width: '760px', data: { ...sample } });
141	    await firstValueFrom(ref.afterClosed());
142	    // Photos may have changed -> reload so the grid thumbnail stays in sync.
143	    await this.loadSamples();
144	  }
145	
146	  async onManageBoxes(): Promise<void> {
147	    await this.openBoxesDialog();
148	  }
149	
150	  async onNewBox(): Promise<void> {
151	    await this.openBoxesDialog('boxes');
152	  }
153	
154	  private async openBoxesDialog(initialTab: 'boxes' | 'groups' = 'boxes'): Promise<void> {
155	    const ref = this.dialog.open(BoxGroupDialogComponent, {
156	      width: '760px',
157	      data: { selectedSampleIds: this.getSelectedIds(), initialTab }
158	    });
159	    const result = await firstValueFrom(ref.afterClosed());
160	    if (result && result.changed) await this.loadSamples();
161	  }
162	
163	  async onNewSample(): Promise<void> {
164	    if (!this.customers.length) await this.loadCustomers();
165	    const ref = this.dialog.open(CreateDialogComponent, {
166	      width: '760px',
167	      maxWidth: '95vw',
168	      panelClass: 'compact-sample-dialog',
169	      data: { customers: this.customers }
170	    });
171	    const result = await firstValueFrom(ref.afterClosed());
172	    if (!result) return;
173	    // __photoFile is carried by the dialog only; strip it before persisting.
174	    const photoFile: File | null = result.__photoFile || null;
175	    delete result.__photoFile;
176	    try {
177	      const created: any = await firstValueFrom(this.trackingService.createSample(result));
178	      if (photoFile && created && created.sample_id_pk != null) {
179	        try {
180	          await this.uploadSamplePhoto(created.sample_id_pk, photoFile, true);
181	        } catch {
182	          this.toast('Sample created, but photo upload failed');
183	          await this.loadSamples();
184	          return;
185	        }
186	      }
187	      this.toast('Sample created');
188	      await this.loadSamples();
189	    } catch (e: any) {
190	      this.toast(this.errMsg(e, 'Failed to create sample'));
191	    }
192	  }
193	
194	  // Presigned upload flow (mirrors detail-dialog): presign -> PUT to storage ->
195	  // make public -> register the attachment against the sample.
196	  private async uploadSamplePhoto(sampleId: number, file: File, primary: boolean): Promise<void> {
197	    const safe = file.name.toLowerCase().replace(/[^a-z0-9.\-]+/g, '-');
198	    const fileName = `samples/sample-${sampleId}-${new Date().getTime()}-${safe}`;
199	    const contentType = file.type || 'image/jpeg';
200	    const presign: any = await firstValueFrom(this.trackingService.getSamplePreSignedUrl({ fileName, contentType }));
201	    const putRes = await fetch(presign.url, { method: 'PUT', body: file, headers: { 'Content-Type': contentType } });
202	    if (!putRes.ok) throw new Error('upload failed');
203	    const pub: any = await firstValueFrom(this.trackingService.setSampleObjectPublic({ fileName }));
204	    await firstValueFrom(this.trackingService.addSamplePhoto({
205	      sample_id_fk: sampleId,
206	      attachment_link: pub.publicUrl,
207	      sample_attachment_fileName: fileName,
208	      attachment_type: contentType,
209	      primary_image: primary
210	    }));
211	  }
212	
213	  async onRecordEvent(): Promise<void> {
214	    const row = this.getSelected();
215	    if (!row) { this.toast('Select a sample first'); return; }
216	    const ref = this.dialog.open(EventDialogComponent, {
217	      width: '440px',
218	      data: {
219	        sample_id_pk: row.sample_id_pk,
220	        sample_name: row.sample_name,
221	        direction: row.direction,
222	        status: row.status,
223	        office_location: row.office_location
224	      }
225	    });
226	    const result = await firstValueFrom(ref.afterClosed());
227	    if (!result) return;
228	    try {
229	      await firstValueFrom(this.trackingService.recordSampleEvent(result));
230	      this.toast('Event recorded');
231	      await this.loadSamples();
232	    } catch (e: any) {
233	      this.toast(this.errMsg(e, 'Could not record event'));
234	    }
235	  }
236	
237	  async onDelete(): Promise<void> {
238	    const row = this.getSelected();
239	    if (!row) { this.toast('Select a sample first'); return; }
240	    if (!confirm(`Delete sample "${row.sample_name || row.sample_id_pk}"? This also removes its photos, comments and history.`)) return;
241	    try {
242	      await firstValueFrom(this.trackingService.deleteSample(row.sample_id_pk));
243	      this.toast('Sample deleted');
244	      await this.loadSamples();
245	    } catch (e: any) {
246	      this.toast(this.errMsg(e, 'Failed to delete sample'));
247	    }
248	  }
249	
250	  async onCellValueChanged(event: CellValueChangedEvent): Promise<void> {
251	    const field = event.colDef.field;
252	    if (!field) return;
253	    const id = event.data.sample_id_pk;
254	    try {
255	      await firstValueFrom(this.trackingService.updateSample(id, { [field]: event.newValue }));
256	    } catch (e: any) {
257	      this.toast(this.errMsg(e, 'Update failed'));
258	      await this.loadSamples(); // revert to server truth
259	    }
260	  }
261	
262	  refresh(): void { this.loadSamples(); }
263	
264	  private errMsg(e: any, fallback: string): string {
265	    return (e && e.error && e.error.message) ? e.error.message : fallback;
266	  }
267	  private toast(msg: string): void {
268	    this.snackBar.open(msg, 'Dismiss', { duration: 4000 });
269	  }
270	}
