1	import { Injectable } from '@angular/core'
2	import { Observable, pipe } from 'rxjs'
3	import { HttpClient, HttpParams } from '@angular/common/http'
4	import { map, catchError } from 'rxjs/operators';
5	import { HttpHeaders } from '@angular/common/http';
6	import { environment } from '../../../environments/environment';
7	@Injectable({
8	  providedIn: 'root',
9	})
10	export class TrackingService {
11	  serverAddress = environment.tracking;
12	  constructor(private http: HttpClient) {
13	  }
14	  setUserAuth() {
15	    let token = localStorage.getItem("token")
16	    const headers = new HttpHeaders()
17	      .set('Authorization', token)
18	    return headers
19	  }
20	
21	  setUserAuthWithLoader() {
22	    let token = localStorage.getItem("token")
23	    const headers = new HttpHeaders()
24	      .set('Authorization', token)
25	      .set('X-Enable-Loader', 'true')
26	    return headers
27	  }
28	
29	  getProdOrderHeader(pagination: { startRow?: number, endRow?: number, filterModel?: string}) {
30	    // Set defaults in the service method
31	    const startRow = pagination.startRow ?? 0
32	    const endRow = pagination.endRow ?? 100
33	    const filterModel = pagination.filterModel
34	
35	    const params = new HttpParams()
36	      .set('startRow', startRow.toString())
37	      .set('endRow', endRow.toString())
38	      .set('filterModel', JSON.stringify(filterModel))
39	
40	    return this.http.get(`${this.serverAddress}/getProdOrderHeader`, {
41	      headers: this.setUserAuthWithLoader(),
42	      params
43	    });
44	  }
45	  getViewlayout(grid_id) {
46	    return this.http.get(`${this.serverAddress}/getViewlayout/${grid_id}`, { headers: this.setUserAuth() })
47	  }
48	  updateProdOrderHeader(data) {
49	    return this.http.post(this.serverAddress + '/updateProdOrderHeader', data, { headers: this.setUserAuth() })
50	  }
51	
52	  /**
53	   * Factory screen production orders — same pagination contract as getProdOrderHeader (startRow, endRow, filterModel).
54	   * Rows include prodReferenceNo for dropdown labels; scoped by factoryId + vendor (same rules as before).
55	   */
56	  getFactoryProdOrderList(
57	    factoryId: number | null,
58	    pagination?: { startRow?: number; endRow?: number; filterModel?: Record<string, unknown> }
59	  ) {
60	    const startRow = pagination?.startRow ?? 0;
61	    const endRow = pagination?.endRow ?? startRow + 10000;
62	    const filterModel = pagination?.filterModel ?? {};
63	
64	    let params = new HttpParams()
65	      .set('startRow', String(startRow))
66	      .set('endRow', String(endRow))
67	      .set('filterModel', JSON.stringify(filterModel));
68	
69	    if (factoryId !== undefined && factoryId !== null) {
70	      params = params.set('factoryId', String(factoryId));
71	    }
72	
73	    return this.http.get(`${this.serverAddress}/factoryProdOrders`, {
74	      headers: this.setUserAuthWithLoader(),
75	      params
76	    });
77	  }
78	
79	  updateFactoryProdOrderDates(body: {
80	    id: number;
81	    material_arrival_date: string | null;
82	    mass_prod_start_date: string | null;
83	    assembly_start_date: string | null;
84	    actual_prod_complete: string | null;
85	    packing_start_date: string | null;
86	    qc_inspection_date: string | null;
87	    actual_etd: string | null;
88	  }) {
89	    return this.http.post(`${this.serverAddress}/factoryProdOrderDates`, body, { headers: this.setUserAuth() });
90	  }
91	
92	  getProdTrackingDetails() {
93	    return this.http.get(this.serverAddress + '/getProdTrackingDetails', { headers: this.setUserAuth() })
94	  }
95	
96	  // ----------------------------- Sample tracking -----------------------------
97	  // Server-side grid contract: ?startRow&endRow&filterModel -> { rows, totalCount }
98	  getSamples(pagination: { startRow?: number; endRow?: number; filterModel?: any }) {
99	    const startRow = pagination.startRow ?? 0
100	    const endRow = pagination.endRow ?? 100
101	    const params = new HttpParams()
102	      .set('startRow', String(startRow))
103	      .set('endRow', String(endRow))
104	      .set('filterModel', JSON.stringify(pagination.filterModel ?? {}))
105	    return this.http.get(`${this.serverAddress}/sample/list`, { headers: this.setUserAuthWithLoader(), params })
106	  }
107	
108	  getSample(id: number) {
109	    return this.http.get(`${this.serverAddress}/sample/${id}`, { headers: this.setUserAuth() })
110	  }
111	
112	  createSample(body: any) {
113	    return this.http.post(`${this.serverAddress}/sample`, body, { headers: this.setUserAuth() })
114	  }
115	
116	  updateSample(id: number, body: any) {
117	    return this.http.put(`${this.serverAddress}/sample/${id}`, body, { headers: this.setUserAuth() })
118	  }
119	
120	  deleteSample(id: number) {
121	    return this.http.delete(`${this.serverAddress}/sample/${id}`, { headers: this.setUserAuth() })
122	  }
123	
124	  // Bidirectional check-in/out engine. body: { sample_id_fk, event_type, office_location, notes?, to_status? }
125	  recordSampleEvent(body: any) {
126	    return this.http.post(`${this.serverAddress}/sample/events`, body, { headers: this.setUserAuth() })
127	  }
128	
129	  getSampleEvents(id: number) {
130	    return this.http.get(`${this.serverAddress}/sample/${id}/events`, { headers: this.setUserAuth() })
131	  }
132	
133	  // Comments
134	  getSampleComments(id: number) {
135	    return this.http.get(`${this.serverAddress}/sample/${id}/comments`, { headers: this.setUserAuth() })
136	  }
137	  addSampleComment(body: any) {
138	    return this.http.post(`${this.serverAddress}/sample/comments`, body, { headers: this.setUserAuth() })
139	  }
140	  updateSampleComment(id: number, body: any) {
141	    return this.http.put(`${this.serverAddress}/sample/comments/${id}`, body, { headers: this.setUserAuth() })
142	  }
143	  deleteSampleComment(id: number) {
144	    return this.http.delete(`${this.serverAddress}/sample/comments/${id}`, { headers: this.setUserAuth() })
