85	// Server-side grid contract: ?startRow&endRow&filterModel -> { rows, totalCount }
86	Sample.list = async (req, result) => {
87	  const { startRow, endRow, filterModel } = req.query;
88	  const limit = endRow != null && startRow != null ? Number(endRow) - Number(startRow) : 100;
89	  const offset = startRow != null ? Number(startRow) : 0;
90	
91	  try {
92	    const user = await getUserInfo(req.headers.authorization);
93	    const filters = filterModel ? JSON.parse(filterModel) : {};
94	    const whereClause = {};
95	
96	    Object.entries(filters).forEach(([field, filterDef]) => {
97	      if (!FILTERABLE.has(field)) return;
98	      // Normalise AG Grid "multi" filters the same way lic.model does.
99	      let def = filterDef;
100	      if (def && def.filterType === 'multi') {
101	        def = (def.filterModels || []).find(sub => sub) || null;
102	      }
103	      const condition = buildCondition(def);
104	      if (condition) whereClause[field] = condition;
105	    });
106	
107	    if (user?.role === 'vendor') {
108	      if (user.factory_id == null || Number.isNaN(Number(user.factory_id))) {
109	        return result(null, { rows: [], totalCount: 0 });
110	      }
111	      whereClause.factory_id_fk = Number(user.factory_id);
112	    }
113	
114	    // The grid page is a plain paginated scan of `sample`. We deliberately do NOT
115	    // join `sample_attachment` here: a `findAndCountAll({distinct:true, include:
116	    // hasMany})` makes Postgres LEFT JOIN every attachment, de-duplicate, and run
117	    // COUNT(DISTINCT ...) — which made /sample/list take 10-30s once any sample had
118	    // photos (it blew past the BFF 30s timeout → "Failed to load samples"). Without
119	    // the include the count is a trivial COUNT(*) and the page uses the PK index for
120	    // ORDER BY sample_id_pk DESC LIMIT. Photos and box labels are added below via
121	    // separate, batched, index-backed lookups (the same shape as the box query).
122	    const { count, rows } = await sql.sample.findAndCountAll({
123	      where: whereClause,
124	      order: [['sample_id_pk', 'DESC']],
125	      limit,
126	      offset
127	    });
128	
129	    const mapped = rows.map(r => (r && typeof r.get === 'function') ? r.get({ plain: true }) : r);
130	
131	    // Surface a primary_photo thumbnail URL on each row for the grid (batched).
132	    const sampleIds = mapped.map(r => r.sample_id_pk).filter(v => v != null);
133	    if (sampleIds.length && sql.sample_attachment) {
134	      const atts = await sql.sample_attachment.findAll({
135	        where: { sample_id_fk: { [Op.in]: sampleIds } },
136	        attributes: ['sample_id_fk', 'attachment_link', 'primary_image']
137	      });
138	      // Pick one photo per sample: prefer the one flagged primary_image, else any.
139	      const photoBySample = new Map();
140	      atts.forEach(a => {
141	        const p = (a && typeof a.get === 'function') ? a.get({ plain: true }) : a;
142	        const cur = photoBySample.get(p.sample_id_fk);
143	        if (!cur || (p.primary_image && !cur.primary_image)) photoBySample.set(p.sample_id_fk, p);
144	      });
145	      mapped.forEach(r => {
146	        const p = photoBySample.get(r.sample_id_pk);
147	        r.primary_photo = p ? p.attachment_link : null;
148	      });
149	    } else {
150	      mapped.forEach(r => { r.primary_photo = null; });

150	      mapped.forEach(r => { r.primary_photo = null; });
151	    }
152	
153	    // Surface the box label (so the grid shows which box a sample is in).
154	    const boxIds = [...new Set(mapped.map(r => r.box_id_fk).filter(Boolean))];
155	    if (boxIds.length && sql.sample_box) {
156	      const boxes = await sql.sample_box.findAll({ where: { box_id_pk: { [Op.in]: boxIds } } });
157	      const labels = new Map(boxes.map(b => [b.box_id_pk, b.box_label]));
